  1	import * as React from 'react';
  2	
  3	import {
  4	  Flex,
  5	  FlexItem,
  6	  SimpleList,
  7	  SimpleListItem,
  8	  Skeleton,
  9	  Text,
 10	  TextVariants,
 11	  Title,
 12	  TitleSizes,
 13	} from '@patternfly/react-core';
 14	
 15	import { GettingStartedLink } from '../types';
 16	
 17	import GettingStartedLinkExtraContent from './GettingStartedLinkExtraContent';
 18	import GettingStartedMoreLinkContent from './GettingStartedMoreLinkContent';
 19	import { getLinkComponent } from './utils';
 20	
 21	import './GettingStartedSectionContents.scss';
 22	
 23	type GettingStartedSectionContentsProps = {
 24	  description?: string;
 25	  icon?: React.ReactElement;
 26	  id: string;
 27	  links: GettingStartedLink[];
 28	  moreLink?: GettingStartedLink;
 29	  title: string;
 30	  titleColor?: string;
 31	};
 32	
 33	const GettingStartedSectionContents: React.FC<GettingStartedSectionContentsProps> = ({
 34	  description,
 35	  icon,
 36	  id,
 37	  links,
 38	  moreLink,
 39	  title,
 40	  titleColor,
 41	}) => {
 42	  return (
 43	    <Flex
 44	      className="getting-started-section-contents"
 45	      data-test={`card ${id}`}
 46	      direction={{ default: 'column' }}
 47	      grow={{ default: 'grow' }}
 48	    >
 49	      <Title data-test="title" headingLevel="h3" size={TitleSizes.md} style={{ color: titleColor }}>
 50	        {icon ? <span className="getting-started-section-contents__title-icon">{icon}</span> : null}
 51	        {title}
 52	      </Title>
 53	
 54	      {description ? (
 55	        <Text component={TextVariants.small} data-test="description">
 56	          {description}
 57	        </Text>
 58	      ) : null}
 59	
 60	      <Flex direction={{ default: 'column' }} grow={{ default: 'grow' }}>
 61	        {links?.length > 0 ? (
 62	          <SimpleList className="getting-started-section-contents__list" isControlled={false}>
 63	            {links.map((link) => {
 64	              const handleClick = link.onClick;
 65	              return link.loading ? (
 66	                <li key={link.id}>
 67	                  <Skeleton fontSize="sm" />
 68	                </li>
 69	              ) : (
 70	                <span key={link.id}>
 71	                  <SimpleListItem
 72	                    componentProps={
 73	                      link.external
 74	                        ? {
 75	                            'data-test': `item ${link.id}`,
 76	                            href: link.href,
 77	                            rel: 'noopener noreferrer',
 78	                            target: '_blank',
 79	                          }
 80	                        : {
 81	                            'data-test': `item ${link.id}`,
 82	                            to: link.href,
 83	                          }
 84	                    }
 85	                    component={getLinkComponent(link)}
 86	                    componentClassName={link.external ? 'co-external-link' : 'co-goto-arrow'}
 87	                    href={link.href}
 88	                    onClick={handleClick}
 89	                  >
 90	                    {link.title}
 91	                  </SimpleListItem>
 92	                  <GettingStartedLinkExtraContent link={link} />
 93	                </span>
 94	              );
 95	            })}
 96	          </SimpleList>
 97	        ) : null}
 98	      </Flex>
 99	      <FlexItem>
100	        <GettingStartedMoreLinkContent moreLink={moreLink} />
101	      </FlexItem>
102	    </Flex>
103	  );
104	};
105	
106	export default GettingStartedSectionContents;

